import sys
import threading
from collections import deque

MOD = 998244353

def main():
    sys.setrecursionlimit(1 << 25)
    H, W = map(int, sys.stdin.readline().split())
    grid = [list(sys.stdin.readline().strip()) for _ in range(H)]

    # Step 1: Count initial green components
    visited = [[False] * W for _ in range(H)]
    initial_components = 0

    def bfs(r, c):
        q = deque()
        q.append((r, c))
        visited[r][c] = True
        while q:
            x, y = q.popleft()
            for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                nx, ny = x + dx, y + dy
                if 0 <= nx < H and 0 <= ny < W and not visited[nx][ny] and grid[nx][ny] == '#':
                    visited[nx][ny] = True
                    q.append((nx, ny))

    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#' and not visited[i][j]:
                bfs(i, j)
                initial_components += 1

    # Step 2: For each red cell, simulate repainting and compute new component count
    red_cells = []
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                red_cells.append((i, j))

    total = 0
    for i, j in red_cells:
        # Temporarily change cell to green
        grid[i][j] = '#'
        # Reuse visited array, reset it
        for x in range(H):
            for y in range(W):
                visited[x][y] = False
        new_components = 0

        def bfs2(r, c):
            q = deque()
            q.append((r, c))
            visited[r][c] = True
            while q:
                x, y = q.popleft()
                for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < H and 0 <= ny < W and not visited[nx][ny] and grid[nx][ny] == '#':
                        visited[nx][ny] = True
                        q.append((nx, ny))

        for x in range(H):
            for y in range(W):
                if grid[x][y] == '#' and not visited[x][y]:
                    bfs2(x, y)
                    new_components += 1

        # Restore cell to red
        grid[i][j] = '.'
        total += new_components

    # Compute expected value
    total_red = len(red_cells)
    numerator = total
    denominator = total_red

    # Compute modular inverse of denominator
    def modinv(a, mod):
        g, x, y = extended_gcd(a, mod)
        if g != 1:
            return None
        else:
            return x % mod

    def extended_gcd(a, b):
        if a == 0:
            return (b, 0, 1)
        else:
            g, y, x = extended_gcd(b % a, a)
            return (g, x - (b // a) * y, y)

    inv_denominator = modinv(denominator, MOD)
    result = (numerator * inv_denominator) % MOD
    print(result)

threading.Thread(target=main).start()
